__rtSmsAccountId = -1;
__rtTimeout = 10000;
__rtNextStep_Success = -1;
__rtNextStep_Failure = -1;
__rtNextStep = -1;


__makeLocalNodeId = function (nodeId) { 
    if (nodeId !== null && nodeId !== undefined) nodeId = nodeId.toString(); 
    if (!context.currentNode.id) 
        return nodeId; 

    var separator = "-"; 
    var output = context.currentNode.id.split(separator); 

    output[output.length - 1] = nodeId; 
    return output.join(separator); 
}; 

// --------------------------------------------------------------------------- 
// __resolveTemplate 
// Evaluates a string as a JS template literal using variables from scope. 
// If a referenced variable is not in scope the raw string is returned as-is. 
// NOTE: scope must only contain trusted, platform-controlled rt/system vars. 
// --------------------------------------------------------------------------- 
__resolveTemplate = function (tpl, scope) { 
    var keys = Object.keys(scope); 
    var vals = []; 
    for (var i = 0; i < keys.length; i++) { 
        vals.push(scope[keys[i]]); 
    } 
    return new Function(keys.join(','), 'return `' + tpl + '`').apply(null, vals); 
} 
// ---------------------------------------------------------------------------
// __extractParams
// Normalizes config input — accepts either a flat params object or a full
// RTDS operation object ({ Params: {} }). Always returns the flat params.
// ---------------------------------------------------------------------------
__extractParams = function (config) {
    var parsed = typeof config === 'string' ? JSON.parse(config) : config;
    if (parsed && typeof parsed.Params === 'object' && parsed.Params !== null) {
        return parsed.Params;
    }
    return parsed || {};
};

// ---------------------------------------------------------------------------
// __setupConfig
// Parses config and resolves params into component-scoped __rt variables.
// Rules per field (except Active):
//   1. Trim the raw value. Missing key → empty string.
//   2. No ${ present → use as plain string.
//   3. ${ present → evaluate as template literal with call-scope rt/* vars.
//      Unresolvable reference → falls back to the raw string.
// Special coercions: ConfigId → Number, Timeout → Number.
// Returns an object with keys __rt<ParamKey> for each resolved param.
// ---------------------------------------------------------------------------
var callScope = {};

__setupConfig = function (config) {
    var params = __extractParams(config);
    var result = {};

    // Active — boolean only, never template-evaluated
    result.__rtActive = typeof params.Active === 'boolean'
        ? params.Active
        : Boolean(params.Active);

    var keys = Object.keys(params);
    for (var i = 0; i < keys.length; i++) {
        var key = keys[i];
        if (key === 'Active') { continue; }

        var raw = (params[key] !== undefined && params[key] !== null)
            ? String(params[key]).trim()
            : '';

        var resolved;
        if (raw.indexOf('${') !== -1) {
            try {
                resolved = __resolveTemplate(raw, callScope);
            } catch (e) {
                log_debug('[__setupConfig] Template resolve failed for key "' + key + '", falling back to raw. Error: ' + e.message);
                resolved = raw;
            }
        } else {
            resolved = raw;
        }

        if (key === 'ConfigId') {
            resolved = Number(resolved) || __rtConfigId;
        } else if (key === 'Timeout') {
            resolved = resolved !== '' ? Number(resolved) : __rtTimeout;
        }

        result['__rt' + key] = resolved;
    }

    return result;
};

// ---------------------------------------------------------------------------
// __init
// Walks params and writes values into the corresponding global __rt* variable.
// Variable lookup order for a param key (e.g. "Body"):
//   1. "__rt"    + key  →  __rtBody
//   2. "__rtSms" + key  →  __rtSmsBody
// The first candidate that already exists as an own property of global is used.
// If neither exists the param is skipped.
// Template references (${varName}) are resolved from global.
// Unresolvable templates log a warning and leave the target at its default.
// ---------------------------------------------------------------------------
__init = function (config) {
    var params = __extractParams(config);

    for (var key in params) {
        if (!params.hasOwnProperty(key)) { continue; }

        var candidates = ['__rt' + key, '__rtSms' + key];
        var targetVar = null;
        for (var i = 0; i < candidates.length; i++) {
            if (global.hasOwnProperty(candidates[i])) {
                targetVar = candidates[i];
                break;
            }
        }
        if (targetVar === null) { continue; }

        var raw = (params[key] !== null && params[key] !== undefined)
            ? String(params[key])
            : '';

        if (raw.indexOf('${') !== -1) {
            var match = raw.match(/^\$\{([^}]+)\}$/);
            if (match && global.hasOwnProperty(match[1])) {
                global[targetVar] = String(global[match[1]]);
            } else {
                log_debug('[__init] Could not resolve template "' + raw + '" for key "' + key + '" — leaving default: ' + global[targetVar]);
            }
            continue;
        }

        global[targetVar] = raw.trim();
    }
};

__isMobileNumber = function(phone) { 
    if (phone == null || phone === '') { return false; } 

    // Normalize: remove spaces, dashes, parentheses, dots 
    var normalized = String(phone).replace(/[\s\-().]/g, ''); 

    // Convert 00-prefixed international to + form 
    if (normalized.indexOf('00') === 0) { 
        normalized = '+' + normalized.slice(2); 
    } 

    // E.164: + followed by 7–15 digits 
    // National (no prefix): 7–15 digits only 
    var intl = /^\+[1-9]\d{6,14}$/; 
    var national = /^[1-9]\d{6,14}$/; 

    return intl.test(normalized) || national.test(normalized); 
} 

// --------------------------------------------------------------------------- 
