__sendSMS = function () {
    log_debug('[SendSMS]: entered function');
    log_debug('[SendSMS]: base= ' + _baseUrl);
    log_debug('[SendSMS]: fullUrl = ' + _baseUrl + _smsApi);
    log_debug('[SendSMS]: to=' + __rtSmsTo);
    log_debug('[SendSMS]: timeout=' + __rtTimeout);
    log_debug('[SendSMS]: accountId=' + __rtSmsAccountId);

    var url = _baseUrl + _smsApi;
    var timeout = (__rtTimeout && __rtTimeout > 0) ? __rtTimeout : 10;

    var payload = {
        smsAccountId: Number(__rtSmsAccountId),
        routing: __rtSmsRouting,
        from: __rtSmsFrom,
        to: __rtSmsTo,
        content: __rtSmsBody,
        plannedTime: new Date().toISOString()
    };

    log_debug('[SendSMS]: calling jsonHttpRequest url=' + url + ' timeout=' + (timeout * 1000));
    log_debug('[SendSMS]: payload=' + JSON.stringify(payload));

    var task;

    try {
        task = jsonHttpRequest(url, { method: 'POST' }, _headers, payload)
            .withTimeout(timeout * 1000);
    } catch (syncErr) {
        log_error('[SendSMS]: jsonHttpRequest sync throw - ' + String(syncErr && (syncErr.message || syncErr)));
        global[__outputVar] = __rtNextStep_Failure;
        return __rtNextStep_Failure;
    }

    log_debug('[SendSMS]: task created, calling .then()');

    return task.then(
        function (result) {
            log_debug('[SendSMS]: success callback fired - result=' + JSON.stringify(result));

            if (!result) {
                log_error('[SendSMS]: empty response');
                global[__outputVar] = __rtNextStep_Failure;
                return __rtNextStep_Failure;
            }

            if (result.success === true && result.statusCode >= 200 && result.statusCode < 300) {
                log_debug('[SendSMS]: REST success');
                global[__outputVar] = __rtNextStep_Success;
                return __rtNextStep_Success;
            }

            if (result.statusCode === 400) {
                log_error('[SendSMS]: validation error - response=' + JSON.stringify(result));
            } else if (result.statusCode === 401 || result.statusCode === 403) {
                log_error('[SendSMS]: authorization error - response=' + JSON.stringify(result));
            } else if (result.statusCode === 404) {
                log_error('[SendSMS]: endpoint not found - response=' + JSON.stringify(result));
            } else if (result.statusCode >= 500) {
                log_error('[SendSMS]: server error - response=' + JSON.stringify(result));
            } else if (result.error && result.error !== '') {
                log_error('[SendSMS]: proxy/request error in result - error=' + result.error + ' response=' + JSON.stringify(result));
            } else {
                log_error('[SendSMS]: generic API failure - response=' + JSON.stringify(result));
            }

            global[__outputVar] = __rtNextStep_Failure;
            return __rtNextStep_Failure;
        },
        function (e) {
            log_error('[SendSMS]: request exception - ' + String(e && (e.message || e)));
            global[__outputVar] = __rtNextStep_Failure;
            return __rtNextStep_Failure;
        }
    );
};

