[ 
    { 
        "name": "__configJSON", 
        "title": "Operation config (JSON)", 
        "hint": "Full RTDS operation Params object as JSON. Must include all required Params fields for the operation type.", 
        "controlSettings": { 
            "controlType": "text", 
            "maxLength": 5000, 
            "dataType": "string", 
            "readonly": false 
        } 
    }, 
    { 
        "name": "__environment", 
        "title": "Environment", 
        "hint": "Deployment environment. Controls which RTDS API endpoint is called.", 
        "controlSettings": { 
            "controlType": "environment", 
            "defaultValue": "acc", 
            "maxLength": 100, 
            "dataType": "string", 
            "readonly": false 
        } 
    }, 
    { 
        "name": "__nextStep", 
        "title": "Next step (output variable name)", 
        "hint": "Name of the session variable that will receive the next step Id after execution. Defaults to _nextStep.", 
        "controlSettings": { 
            "controlType": "text", 
            "defaultValue": "_nextStep", 
            "maxLength": 100, 
            "dataType": "string", 
            "readonly": false 
        } 
    }, 
    { 
        "name": "__outputVar", 
        "title": "Output variable name", 
        "hint": "Name of the session variable that will receive the result of this operation. Defaults to result.", 
        "controlSettings": { 
            "controlType": "text", 
            "defaultValue": "result", 
            "maxLength": 100, 
            "dataType": "string", 
            "readonly": false 
        } 
    } 
]

