__rtActive = false;
__rtSmsTo = "";
__rtSmsRouting = "";
__rtSmsFrom = "";
__rtSmsBody = "Test sms..";
__rtSmsAccountId = -1;
__rtConfigId = -1;
__rtTimeout = 10000;
__rtNextStep_Success = -1;
__rtNextStep_Failure = -1;
__rtNextStep = -1;

if (!_headers) {
  _headers = {};
}


__init(__configJSON);
log_debug('__configJSON: ' + JSON.stringify(__configJSON));

log_debug('__rtActive: ' + __rtActive);
log_debug('__rtSmsTo: ' + __rtSmsTo);
log_debug('__rtSmsRouting: ' + __rtSmsRouting);
log_debug('__rtSmsFrom: ' + __rtSmsFrom);
log_debug('__rtSmsBody: ' + __rtSmsBody);
log_debug('__rtSmsAccountId: ' + __rtSmsAccountId);
log_debug('__rtConfigId: ' + __rtConfigId);
log_debug('__rtTimeout: ' + __rtTimeout);
log_debug('__rtNextStep_Success: ' + __rtNextStep_Success);
log_debug('__rtNextStep_Failure: ' + __rtNextStep_Failure);
log_debug('__rtNextStep: ' + __rtNextStep);

global[_rtNextStep] = __rtNextStep;



if (!__rtActive) {

    log_debug("[sendSms] Inactive.");

    return;

}

if (!__rtSmsTo || __rtSmsTo.trim() === "") {

    log_debug("[sendSms] SmsTo field is empty.");

    return;

}

if (!__isMobileNumber(__rtSmsTo)) {

    log_debug("[sendSms] Phone classification not matched.");

    return;

}



log_debug("[sendSms] Phone number valid");



global[_rtNextStep] = __rtNextStep_Failure;



var url = __rtBaseUrl + __rtEndpoint;

var timeout = (__rtTimeout && __rtTimeout > 0) ? __rtTimeout : 10;



var payload = {

    smsAccountId: Number(__rtSmsAccountId),

    routing: __rtSmsRouting,

    from: __rtSmsFrom,

    to: __rtSmsTo,

    content: __rtSmsBody,

    plannedTime: new Date().toISOString()

};



var result = null;

return jsonHttpRequest(url, { method: 'POST' }, _headers, payload)

    .then(function (result) {

        log_debug('[sendSms]: result=' + JSON.stringify(result));

        if ( result && result.success === true ) {

            log_debug('[sendSms]: REST success');

            global[__nextStep] = __rtNextStep_Success;

            return;

        }

        log_error('[sendSms]: request failed - ' + JSON.stringify(result));

    }, function (err) {

        log_error('[sendSms]: request failed => ' + JSON.stringify(err));

    });
